  // ============================================
  // WF-NEW-1: NORMALIZAR PAYLOAD - V11
  // ADICIONADO: Debug para mensagens automáticas
  // ============================================

  const input = $input.first().json;
  const body = input.body || input;
  const headers = input.headers || {};

  // ============================================
  // DEBUG: REGISTRAR TUDO QUE CHEGA NO WEBHOOK
  // ============================================
  console.log('=== WEBHOOK RECEBIDO ===');
  console.log('Timestamp:', new Date().toISOString());
  console.log('Body keys:', Object.keys(body));
  console.log('Headers:', JSON.stringify(headers).substring(0, 200));
  console.log('Body preview:', JSON.stringify(body).substring(0, 500));

  // ============================================
  // IGNORAR WEBHOOKS DO CHATWOOT
  // ============================================
  if (body.event === 'message_created' || body.event === 'message_updated') {
    console.log('⏭️ IGNORADO: Webhook do Chatwoot');
    return [{
      json: {
        skip: true,
        reason: 'Webhook do Chatwoot - ignorar no WF-INBOUND',
        platform: 'chatwoot',
        event: body.event
      }
    }];
  }

  if (body.account && body.conversation && body.inbox && !body.owner && !body.messages) {
    console.log('⏭️ IGNORADO: Payload do Chatwoot detectado');
    return [{
      json: {
        skip: true,
        reason: 'Payload do Chatwoot detectado - ignorar',
        platform: 'chatwoot'
      }
    }];
  }

  // ============================================
  // CONFIGURAÇÃO DE INBOXES
  // ============================================
  const INBOX_MAP = {
    '556192894339': { inboxId: 5, name: 'EEG' },
    '556183008973': { inboxId: 4, name: 'Recepção' },
    '556133455701': { inboxId: 8, name: 'Geral (360Dialog)' }
  };

  // ============================================
  // MAPEAMENTO DE GRUPOS PARA INBOXES SEPARADOS
  // ============================================
  const GROUP_INBOX_MAP = {
    4: 10,  // Recepção → Grupos Recepção
    5: 11   // EEG → Grupos EEG
  };

  // ============================================
  // FUNÇÃO DE NORMALIZAÇÃO DE TELEFONE
  // ============================================
  function normalizePhone(phone) {
    if (!phone) return null;
    if (phone.includes('@g.us')) return phone;

    let cleaned = phone
      .replace('@s.whatsapp.net', '')
      .replace('@lid', '')
      .replace(/\D/g, '');

    if (cleaned.startsWith('0')) cleaned = cleaned.substring(1);
    if (!cleaned.startsWith('55')) cleaned = '55' + cleaned;

    if (cleaned.length === 12) {
      const countryCode = cleaned.substring(0, 2);
      const ddd = cleaned.substring(2, 4);
      const number = cleaned.substring(4);
      cleaned = countryCode + ddd + '9' + number;
    }

    if (cleaned.length < 10 || cleaned.length > 15) return null;
    return cleaned;
  }

  // ============================================
  // DETECTAR PLATAFORMA
  // ============================================
  let platform = 'unknown';
  let normalizedMessage = null;

  if (body.owner && body.message) {
    platform = 'uazapi';
  } else if (body.messages && Array.isArray(body.messages)) {
    platform = '360dialog';
  } else if (body.entry || body.object === 'whatsapp_business_account') {
    platform = '360dialog';
  }

  console.log('📱 Plataforma detectada:', platform);

  // ============================================
  // NORMALIZAR UAZAPI
  // ============================================
  if (platform === 'uazapi') {
    const msg = body.message || {};
    const chat = body.chat || {};
    const owner = body.owner || '';

    // Ignorar mensagens enviadas por nós (fromMe)
    if (msg.fromMe === true) {
      console.log('⏭️ IGNORADO: Mensagem fromMe (enviada por nós)');
      return [{
        json: {
          skip: true,
          reason: 'Mensagem enviada por nós (fromMe)',
          platform: platform
        }
      }];
    }

    // Ignorar status updates
    if (body.EventType && body.EventType !== 'messages') {
      if (body.EventType === 'messages_update') {
      console.log('📋 STATUS UPDATE CAPTURADO:', JSON.stringify(body).substring(0, 500));
      return [{
        json: {
          skip: true,
          reason: 'Status update capturado para debug',
          debugPayload: body
        }
      }];
    }
    console.log('⭕ IGNORADO: EventType =', body.EventType);
    return [{
      json: {
        skip: true,
        reason: `Evento ignorado: ${body.EventType}`,
        platform: platform
      }
    }];
  }

    // Determinar inbox
    const inboxConfig = INBOX_MAP[owner] || { inboxId: 5, name: 'Default' };

    // Extrair informações do contato/grupo
    const isGroup = chat.wa_isGroup === true || msg.isGroup === true;

    // ============================================
    // REDIRECIONAR GRUPOS PARA INBOX SEPARADO
    // ============================================
    let finalInboxId = inboxConfig.inboxId;
    let finalInboxName = inboxConfig.name;

    if (isGroup && GROUP_INBOX_MAP[inboxConfig.inboxId]) {
      finalInboxId = GROUP_INBOX_MAP[inboxConfig.inboxId];
      finalInboxName = inboxConfig.inboxId === 4 ? 'Grupos Recepção' : 'Grupos EEG';
    }

    // Foto do contato/grupo
    const avatarUrl = chat.imagePreview || chat.image || null;

    // ============================================
    // EXTRAIR TELEFONES E NOMES
    // ============================================
    let rawContactPhone = '';
    let rawSenderPhone = '';
    let groupId = null;
    let groupName = null;
    let contactName = '';
    let senderName = '';

    if (isGroup) {
      rawContactPhone = chat.wa_chatid || msg.chatid || '';
      groupId = rawContactPhone;

      groupName = msg.groupName && msg.groupName !== 'Unknown' ? msg.groupName : null
                || chat.subject      
                || chat.wa_name
                || chat.name
                || chat.groupName    
                || groupId;

      contactName = groupName;

      rawSenderPhone = msg.sender_pn || msg.sender || '';
      senderName = msg.senderName || msg.pushName || msg.sender_name || '';

      if (!senderName && rawSenderPhone) {
        senderName = normalizePhone(rawSenderPhone) || rawSenderPhone;
      }

    } else {
      rawContactPhone = msg.sender_pn || chat.wa_chatid || chat.phone || '';
      rawSenderPhone = rawContactPhone;
      contactName = chat.wa_name || chat.name || chat.wa_contactName || '';

      if (!contactName) {
        contactName = normalizePhone(rawContactPhone) || rawContactPhone;
      }

      senderName = msg.senderName || contactName;
    }

    const contactPhone = isGroup ? rawContactPhone : normalizePhone(rawContactPhone);
    const senderPhone = normalizePhone(rawSenderPhone);

    // ============================================
    // DETECTAR MÍDIA - PRIORIDADE PARA PTT/ÁUDIO
    // ============================================
    const msgType = msg.type || '';
    const mediaType = msg.mediaType || '';
    const messageType = msg.messageType || '';

    let hasMedia = false;
    let detectedMediaType = null;
    let mediaUrl = null;
    let mimeType = null;
    let fileName = null;

    // ============================================
    // v10: DETECTAR LOCALIZAÇÃO (UAZAPI)
    // ============================================
    let latitude = null;
    let longitude = null;
    let locationName = null;
    let locationAddress = null;

    if (msgType === 'location' || messageType === 'LocationMessage' || msg.location) {
      const loc = msg.location || msg.content || {};
      latitude = loc.degreesLatitude || loc.latitude || null;
      longitude = loc.degreesLongitude || loc.longitude || null;
      locationName = loc.name || null;
      locationAddress = loc.address || null;
      detectedMediaType = 'location';
      console.log('✅ Localização detectada (UAZAPI):', latitude, longitude);
    }

    // ============================================
    // PRIMEIRO: Verificar se tem URL no content
    // ============================================
    if (!detectedMediaType && msg.content && typeof msg.content === 'object') {
      const contentUrl = msg.content.URL || msg.content.url;
      const contentMime = msg.content.mimetype || msg.content.mimeType;

      if (contentUrl) {
        hasMedia = true;
        mediaUrl = contentUrl;
        mimeType = contentMime || null;
        fileName = msg.content.fileName || msg.content.filename || null;

        // Detectar se é PTT pelo campo PTT ou pelo mimetype
        if (msg.content.PTT === true || mediaType === 'ptt') {
          detectedMediaType = 'audio';
          console.log('✅ PTT detectado via content.PTT ou mediaType');
        }
        // Detectar tipo pela mimetype
        else if (contentMime) {
          if (contentMime.startsWith('image/')) {
            detectedMediaType = 'image';
          } else if (contentMime.startsWith('video/')) {
            detectedMediaType = 'video';
          } else if (contentMime.startsWith('audio/') || contentMime.includes('ogg') || contentMime.includes('opus')) {
            detectedMediaType = 'audio';
          } else {
            detectedMediaType = 'document';
          }
        }
      }
    }

    // ============================================
    // SEGUNDO: Verificar campos de tipo
    // ============================================
    if (!detectedMediaType) {
      // PTT específico
      if (mediaType === 'ptt' || msgType === 'ptt' || messageType === 'PttMessage') {
        hasMedia = true;
        detectedMediaType = 'audio';
        if (!mimeType) mimeType = 'audio/ogg; codecs=opus';
        console.log('✅ PTT detectado via mediaType/msgType/messageType');
      }
      // AudioMessage
      else if (messageType === 'AudioMessage' || mediaType === 'audio') {
        hasMedia = true;
        detectedMediaType = 'audio';
        console.log('✅ Áudio detectado via messageType/mediaType');
      }
      // Outros tipos de mídia
      else if (msgType === 'media' || ['image', 'video', 'document', 'sticker', 'voice'].includes(mediaType)) {
        hasMedia = true;
        detectedMediaType = mediaType || 'document';

        // Normalizar voice para audio
        if (detectedMediaType === 'voice') {
          detectedMediaType = 'audio';
        }
      }
      // Por messageType
      else if (['ImageMessage', 'VideoMessage', 'DocumentMessage', 'StickerMessage'].some(t => messageType.includes(t.replace('Message', '')))) {
        hasMedia = true;
        detectedMediaType = messageType.replace('Message', '').toLowerCase();
      }
    }

    // ============================================
    // TERCEIRO: Fallback para campos diretos
    // ============================================
    if (hasMedia && !mediaUrl) {
      mediaUrl = msg.mediaUrl || msg.media || null;
    }
    if (!mimeType) {
      mimeType = msg.mimetype || msg.mimeType || null;
    }
    if (!fileName) {
      fileName = msg.filename || msg.fileName || null;
    }

    // ============================================
    // EXTRAIR CONTEÚDO DE TEXTO
    // ============================================
    let content = '';

    if (typeof msg.text === 'string' && msg.text) {
      content = msg.text;
    } else if (typeof msg.content === 'string' && msg.content) {
      content = msg.content;
    } else if (msg.content && typeof msg.content === 'object') {
      // Para mídia, o texto pode estar em caption
      content = msg.content.caption || msg.content.text || '';
    } else if (msg.caption) {
      content = msg.caption;
    }

    // ============================================
    // LOG DE DEBUG PARA MÍDIA
    // ============================================
    if (hasMedia) {
      console.log('=== DEBUG MÍDIA ===');
      console.log('hasMedia:', hasMedia);
      console.log('detectedMediaType:', detectedMediaType);
      console.log('mediaUrl:', mediaUrl ? 'SIM (URL presente)' : 'NÃO');
      console.log('mimeType:', mimeType);
      console.log('msg.mediaType:', mediaType);
      console.log('msg.messageType:', messageType);
      console.log('msg.type:', msgType);
    }

    // ============================================
    // LOG DE DEBUG PARA REDIRECIONAMENTO DE GRUPOS
    // ============================================
    if (isGroup) {
      console.log('=== DEBUG GRUPO ===');
      console.log('isGroup:', isGroup);
      console.log('Original inboxId:', inboxConfig.inboxId);
      console.log('Final inboxId:', finalInboxId);
      console.log('Final inboxName:', finalInboxName);
    }

    // ============================================
    // VALIDAÇÃO: MÍDIA SEM URL
    // ============================================
    if (hasMedia && !mediaUrl) {
      console.log('⚠️ Mídia detectada sem URL disponível');

      if (!content) {
        content = '[' + (detectedMediaType || 'Mídia') + ' não disponível]';
      }
    }

    // Validar telefone
    if (!contactPhone) {
      console.log('⏭️ IGNORADO: Telefone inválido');
      return [{
        json: {
          skip: true,
          reason: 'Telefone inválido ou não encontrado',
          platform: platform,
          rawPhone: rawContactPhone
        }
      }];
    }

    // Validar que tem conteúdo ou mídia ou localização
    if (!content && !hasMedia && !latitude) {
      console.log('⏭️ IGNORADO: Sem conteúdo, mídia ou localização');
      return [{
        json: {
          skip: true,
          reason: 'Mensagem sem conteúdo, sem mídia e sem localização',
          platform: platform
        }
      }];
    }

    console.log('✅ Mensagem UAZAPI processada:', contactPhone, content.substring(0, 50));

    normalizedMessage = {
      messageId: msg.id || `${owner}:${Date.now()}`,
      platform: 'uazapi',
      owner: owner,
      inboxId: finalInboxId,
      inboxName: finalInboxName,

      // Contato/Grupo
      isGroup: isGroup,
      contactPhone: contactPhone,
      contactName: contactName,
      groupId: groupId,
      groupName: groupName,

      // Foto
      avatarUrl: avatarUrl,

      // Remetente
      senderPhone: senderPhone,
      senderName: senderName,

      // Mensagem
      content: content,
      messageType: detectedMediaType || 'text',

      // Mídia
      hasMedia: hasMedia,
      mediaUrl: mediaUrl,
      mimeType: mimeType,
      fileName: fileName,

      // v10: Localização
      latitude: latitude,
      longitude: longitude,
      locationName: locationName,
      locationAddress: locationAddress,

      // Metadata
      timestamp: msg.messageTimestamp || Date.now(),
      receivedAt: new Date().toISOString()
    };
  }

  // ============================================
  // NORMALIZAR 360DIALOG
  // ============================================
  else if (platform === '360dialog') {
    const entry = body.entry?.[0] || body;
    const changes = entry.changes?.[0] || {};
    const value = changes.value || body;
    const messages = value.messages || body.messages || [];
    const contacts = value.contacts || body.contacts || [];

    // ============================================
    // IGNORAR STATUS UPDATES (delivered, read, sent)
    // ============================================
    if (value.statuses || body.statuses) {
      console.log('⏭️ IGNORADO: Status update (delivered/read/sent)');
      return [{
        json: {
          skip: true,
          reason: 'Status update ignorado',
          platform: platform
        }
      }];
    }

    if (messages.length === 0) {
      console.log('⏭️ IGNORADO: Nenhuma mensagem no payload');
      return [{
        json: {
          skip: true,
          reason: 'Nenhuma mensagem no payload 360Dialog',
          platform: platform
        }
      }];
    }

    const msg = messages[0];
    const contact = contacts[0] || {};

    const inboxConfig = INBOX_MAP['556133455701'] || { inboxId: 8, name: 'Geral' };

    const rawContactPhone = msg.from || contact.wa_id || '';
    const contactPhone = normalizePhone(rawContactPhone);
    const contactName = contact.profile?.name || contactPhone;

    const messageType = msg.type || 'text';
    let content = '';
    let mediaUrl = null;
    let mimeType = null;
    let fileName = null;
    let hasMedia = false;
    let detectedMediaType = messageType;

    // ============================================
    // v10: DETECTAR LOCALIZAÇÃO (360Dialog)
    // ============================================
    let latitude = null;
    let longitude = null;
    let locationName = null;
    let locationAddress = null;

    if (messageType === 'location' && msg.location) {
      latitude = msg.location.latitude || null;
      longitude = msg.location.longitude || null;
      locationName = msg.location.name || null;
      locationAddress = msg.location.address || null;
      detectedMediaType = 'location';
      content = `📍 Localização: ${latitude}, ${longitude}`;
      console.log('✅ Localização detectada (360Dialog):', latitude, longitude);
    }

    // ============================================
    // TRATAR MENSAGENS INTERATIVAS (BOTÕES)
    // ============================================
    let buttonId = null;
    let buttonTitle = null;

    if (messageType === 'interactive') {
      const interactive = msg.interactive || {};
      const interactiveType = interactive.type || '';

      if (interactiveType === 'button_reply' && interactive.button_reply) {
        // Clique em botão de resposta rápida
        buttonId = interactive.button_reply.id;
        buttonTitle = interactive.button_reply.title;
        content = buttonId; // Usar o ID do botão como conteúdo
        detectedMediaType = 'interactive_button';
      } else if (interactiveType === 'list_reply' && interactive.list_reply) {
        // Seleção em lista
        buttonId = interactive.list_reply.id;
        buttonTitle = interactive.list_reply.title;
        content = buttonId; // Usar o ID da seleção como conteúdo
        detectedMediaType = 'interactive_list';
      }

      console.log('🔘 Botão/Lista:', buttonId, buttonTitle);
    }
    // ============================================
    // TEXTO NORMAL
    // ============================================
    else if (messageType === 'text') {
      content = msg.text?.body || '';
    } 
    // ============================================
    // MÍDIA (imagem, vídeo, áudio, documento)
    // ============================================
    else if (['image', 'video', 'audio', 'document', 'sticker'].includes(messageType)) {
      hasMedia = true;
      const mediaObj = msg[messageType] || {};
      content = mediaObj.caption || '';
      mediaUrl = mediaObj.id;
      mimeType = mediaObj.mime_type || null;
      fileName = mediaObj.filename || null;
    }

    if (hasMedia && !mediaUrl) {
      if (!content) {
        content = '[' + messageType + ' não disponível]';
      }
    }

    if (!contactPhone) {
      console.log('⏭️ IGNORADO: Telefone inválido');
      return [{
        json: {
          skip: true,
          reason: 'Telefone inválido ou não encontrado',
          platform: platform,
          rawPhone: rawContactPhone
        }
      }];
    }

    // Validar que tem conteúdo ou mídia ou localização
    if (!content && !hasMedia && !latitude) {
      console.log('⏭️ IGNORADO: Sem conteúdo, mídia ou localização');
      return [{
        json: {
          skip: true,
          reason: 'Mensagem sem conteúdo, sem mídia e sem localização',
          platform: platform
        }
      }];
    }

    console.log('✅ Mensagem 360Dialog processada:', contactPhone, content.substring(0, 50));

    normalizedMessage = {
      messageId: msg.id || `360dialog:${Date.now()}`,
      platform: '360dialog',
      owner: '556133455701',
      inboxId: inboxConfig.inboxId,
      inboxName: inboxConfig.name,
      isGroup: false,
      contactPhone: contactPhone,
      contactName: contactName,
      groupId: null,
      groupName: null,
      avatarUrl: null,
      senderPhone: contactPhone,
      senderName: contactName,
      content: content,
      messageType: detectedMediaType,
      hasMedia: hasMedia,
      mediaUrl: mediaUrl,
      mimeType: mimeType,
      fileName: fileName,
      // Campos de botão
      buttonId: buttonId,
      buttonTitle: buttonTitle,
      // v10: Localização
      latitude: latitude,
      longitude: longitude,
      locationName: locationName,
      locationAddress: locationAddress,
      // Metadata
      timestamp: parseInt(msg.timestamp) * 1000 || Date.now(),
      receivedAt: new Date().toISOString()
    };
  }

  // ============================================
  // PLATAFORMA NÃO RECONHECIDA
  // ============================================
  if (!normalizedMessage) {
    console.log('⏭️ IGNORADO: Plataforma não reconhecida:', platform);
    return [{
      json: {
        skip: true,
        reason: `Plataforma não reconhecida: ${platform}`,
        platform: platform,
        body: body
      }
    }];
  }

 // ============================================
// EXTRAIR DADOS PARA CACHE DE CONTATOS
// ============================================

let contactCache = {
  shouldCache: false,
  lid: '',
  phoneNumber: '',
  pushName: '',
  groupId: null,
  owner: ''
};

// Só cachear para UAZAPI e mensagens de grupo
if (platform === 'uazapi' && normalizedMessage && normalizedMessage.isGroup) {
  const msgCache = body.message || {};
  const cacheSenderLid = msgCache.sender || msgCache.sender_lid || '';
  const cacheSenderPhone = (msgCache.sender_pn || '').replace('@s.whatsapp.net', '');
  const cacheSenderName = msgCache.senderName || '';

  contactCache = {
    shouldCache: !!(cacheSenderLid && cacheSenderName),
    lid: cacheSenderLid,
    phoneNumber: cacheSenderPhone,
    pushName: cacheSenderName,
    groupId: msgCache.chatid || null,
    owner: body.owner || ''
  };

  if (contactCache.shouldCache) {
    console.log('📝 Cache de contato preparado:', cacheSenderName, cacheSenderLid);
  }
}

// ============================================
// RETORNAR MENSAGEM NORMALIZADA
// ============================================
console.log('✅ Mensagem normalizada com sucesso');
return [{
  json: {
    skip: false,
    message: normalizedMessage,
    contactCache: contactCache
  }
}];

  // ============================================
  // RETORNAR MENSAGEM NORMALIZADA
  // ============================================
  console.log('✅ Mensagem normalizada com sucesso');
  return [{
    json: {
      skip: false,
      message: normalizedMessage,
      contactCache: contactCache
    }
  }];

const input = $input.first().json;
const message = input.message || input;

// Verificar se é Inbox 8
const isInbox8 = message.inboxId === 8;
const telefone = message.senderPhone || message.contactPhone;

if (!isInbox8) {
  return [{
    json: {
      ...input,
      redirectToHub: false,
      reason: 'Não é Inbox 8'
    }
  }];
}

// Lista de usuários cadastrados no Hub
const USUARIOS_HUB = [
  '5561981220485', '5561991495059', '5561981573841', '5561996628353',
  '5561991474378', '5561996638353', '5561992349256', '5561996714043', 
  '5561981147689', '5561984958038', '5561996723612', 
  '5562994449267', '5561991827054','5565992456963', '5565992707250', '5548988166469',
  '5591982105285', '5561999313834', '5561982081494', '5561981573841'
];

const isUsuarioCadastrado = USUARIOS_HUB.includes(telefone);

if (isUsuarioCadastrado) {
  return [{
    json: {
      redirectToHub: true,
      message: message,
      telefone: telefone
    }
  }];
}

return [{
  json: {
    ...input,
    redirectToHub: false,
    reason: 'Usuário não cadastrado no Hub'
  }
}];
